class TransactionEvent:
    """Represents a financial transaction event."""

    def __init__(self, data: Dict[str, Any]):
        self.transaction_id = data.get('transaction_id', '')
        self.event_type = data.get('event_type', '')
        self.amount = data.get('amount', 0.0)
        self.currency = data.get('currency', 'USD')
        self.sender_account = data.get('sender_account', '')
        self.receiver_account = data.get('receiver_account', '')
        self.timestamp = data.get('timestamp', datetime.utcnow().isoformat())
        self.metadata = data.get('metadata', {})
        self.status = data.get('status', 'pending')
        self.raw_data = data

    def __repr__(self):
        return (
            f"TransactionEvent(id={self.transaction_id}, type={self.event_type}, "
            f"amount={self.amount} {self.currency}, status={self.status})"
        )


class TransactionHandlerRegistry:
    """Registry for dynamically registering and executing message handlers."""

    def __init__(self):
        self._handlers: Dict[str, list[Callable]] = {}
        self._pre_processors: list[Callable] = []
        self._post_processors: list[Callable] = []

    def register_handler(self, event_type: str, handler: Callable) -> None:
        """Register a handler for a specific event type."""
        if event_type not in self._handlers:
            self._handlers[event_type] = []
        self._handlers[event_type].append(handler)
        logger.info(f"Registered handler '{handler.__name__}' for event type '{event_type}'")

    def register_pre_processor(self, processor: Callable) -> None:
        """Register a pre-processor that runs before handlers."""
        self._pre_processors.append(processor)

    def register_post_processor(self, processor: Callable) -> None:
        """Register a post-processor that runs after handlers."""
        self._post_processors.append(processor)

    def execute(self, event: TransactionEvent) -> Dict[str, Any]:
        """Execute all registered handlers for the given event type."""
        results = {
            'event_type': event.event_type,
            'transaction_id': event.transaction_id,
            'handlers_executed': [],
            'errors': [],
            'pre_processing': [],
            'post_processing': []
        }

        # Run pre-processors
        for processor in self._pre_processors:
            try:
                result = processor(event)
                results['pre_processing'].append({
                    'processor': processor.__name__,
                    'result': result
                })
            except Exception as e:
                logger.error(f"Pre-processor '{processor.__name__}' failed: {e}")
                results['errors'].append({
                    'stage': 'pre_processing',
                    'processor': processor.__name__,
                    'error': str(e)
                })

        # Execute handlers
        handlers = self._handlers.get(event.event_type, [])
        if not handlers:
            # Try wildcard handlers
            handlers = self._handlers.get('*', [])

        if not handlers:
            logger.warning(f"No handlers registered for event type: {event.event_type}")
            results['errors'].append({
                'stage': 'handling',
                'error': f'No handlers for event type: {event.event_type}'
            })
            return results

        for handler in handlers:
            try:
                result = handler(event)
                results['handlers_executed'].append({
                    'handler': handler.__name__,
                    'result': result
                })
                logger.info(
                    f"Handler '{handler.__name__}' executed successfully for "
                    f"transaction {event.transaction_id}"
                )
            except Exception as e:
                logger.error(
                    f"Handler '{handler.__name__}' failed for "
                    f"transaction {event.transaction_id}: {e}"
                )
                results['errors'].append({
                    'stage': 'handling',
                    'handler': handler.__name__,
                    'error': str(e)
                })

        # Run post-processors
        for processor in self._post_processors:
            try:
                result = processor(event, results)
                results['post_processing'].append({
                    'processor': processor.__name__,
                    'result': result
                })
            except Exception as e:
                logger.error(f"Post-processor '{processor.__name__}' failed: {e}")
                results['errors'].append({
                    'stage': 'post_processing',
                    'processor': processor.__name__,
                    'error': str(e)
                })

        return results

    def get_registered_types(self) -> list[str]:
        """Return all registered event types."""
        return list(self._handlers.keys())


class MessageDeserializer:
    """Handles deserialization of incoming Kafka messages."""

    @staticmethod
    def deserialize_json(raw_bytes: bytes) -> Dict[str, Any]:
        """Deserialize JSON bytes to dictionary."""
        try:
            return json.loads(raw_bytes.decode('utf-8'))
        except (json.JSONDecodeError, UnicodeDecodeError) as e:
            logger.error(f"Failed to deserialize message: {e}")
            raise

    @staticmethod
    def to_transaction_event(data: Dict[str, Any]) -> TransactionEvent:
        """Convert deserialized data to TransactionEvent."""
        return TransactionEvent(data)


class FraudDetectionService:
    """Simple fraud detection logic."""

    SUSPICIOUS_AMOUNT_THRESHOLD = 10000.0
    HIGH_RISK_COUNTRIES = {'XX', 'YY', 'ZZ'}

    @staticmethod
    def check_amount_threshold(event: TransactionEvent) -> Dict[str, Any]:
        """Check if transaction amount exceeds threshold."""
        is_suspicious = event.amount > FraudDetectionService.SUSPICIOUS_AMOUNT_THRESHOLD
        result = {
            'check': 'amount_threshold',
            'suspicious': is_suspicious,
            'amount': event.amount,
            'threshold': FraudDetectionService.SUSPICIOUS_AMOUNT_THRESHOLD
        }
        if is_suspicious:
            logger.warning(
                f"FRAUD ALERT: Transaction {event.transaction_id} "
                f"amount {event.amount} exceeds threshold"
            )
        return result

    @staticmethod
    def check_high_risk_origin(event: TransactionEvent) -> Dict[str, Any]:
        """Check if transaction originates from high-risk region."""
        country = event.metadata.get('origin_country', '')
        is_high_risk = country in FraudDetectionService.HIGH_RISK_COUNTRIES
        result = {
            'check': 'high_risk_origin',
            'high_risk': is_high_risk,
            'country': country
        }
        if is_high_risk:
            logger.warning(
                f"FRAUD ALERT: Transaction {event.transaction_id} "
                f"from high-risk country: {country}"
            )
        return result


