def validate_transaction(event: TransactionEvent) -> Dict[str, Any]:
    """Pre-processor: Validate transaction data."""
    errors = []
    if not event.transaction_id:
        errors.append('Missing transaction_id')
    if event.amount <= 0:
        errors.append('Invalid amount: must be positive')
    if not event.event_type:
        errors.append('Missing event_type')

    if errors:
        raise ValueError(f"Validation failed: {', '.join(errors)}")

    return {'validation': 'passed'}


